def validate_cart_items(cart): 
    return len(cart.items) > 0 
     
def apply_discount_code(cart, discount_code): 
    if discount_code.permission_tier <= cart.user.permission_tier:
        total_price = sum(item.price for item in cart.items)
        return total_price - total_price*discount_code.discount
    else:
        return None

def calculate_tax(price):
    tax_percentage = 0.06  
    return price + price * tax_percentage 

def process_payment(price):
    return price  

def create_order_record(cart, price):
    return {'user': cart.user.username, 'total_price': price, 'items': [(item.name, item.price) for item in cart.items]}

def checkout_process(cart, discount_code):
    if validate_cart_items(cart):
        total_price = apply_discount_code(cart, discount_code)
        if total_price is None:
            return "User not allowed to use this discount code."
    else:
        return "Invalid cart."
    
    total_price_include_tax = calculate_tax(total_price)
